// ============================================================
// DESIGN SYSTEM
// ============================================================
const D = {
  bg: "0A2540", lightBg: "FFFFFF", glow: "635BFF",
  white: "FFFFFF", text: "EDEDED", muted: "8B95A5", darkText: "1A1F36",
  accent: "635BFF", wrong: "FF6B8A", wrongBg: "FEE2E8", right: "09825D", rightBg: "DCFCE7",
  h: "Georgia", b: "Verdana",
};

// ============================================================
// UTILITIES
// ============================================================
function darkSlide(pres) {
  const s = pres.addSlide();
  s.background = { color: D.bg };
  s.addShape(pres.shapes.OVAL, {
    x: 5, y: 2.5, w: 8, h: 6,
    fill: { color: D.accent, transparency: 96 }
  });
  return s;
}

function hero(pres, main, opts = {}) {
  const s = darkSlide(pres);
  s.addText(main, {
    x: 1.0, y: 1.2, w: 8, h: 2.8,
    fontFace: opts.font || D.h, fontSize: opts.size || 44,
    color: opts.color || D.white, bold: true,
    align: "center", margin: 0, valign: "middle"
  });
  if (opts.sub) {
    s.addText(opts.sub, {
      x: 1.5, y: 4.0, w: 7, h: 0.8,
      fontFace: D.b, fontSize: 28,
      color: opts.subColor || D.muted, align: "center", margin: 0, valign: "top"
    });
  }
  if (opts.notes) s.addNotes(opts.notes);
  return s;
}

function sectionDivider(pres, d) {
  const s = darkSlide(pres);
  s.addText(d.title, {
    x: 0.5, y: 1.6, w: 9, h: 1.2,
    fontFace: D.h, fontSize: 54, color: D.white, bold: true, align: "center", margin: 0
  });
  if (d.subtitle) {
    s.addText(d.subtitle, {
      x: 1.0, y: 2.9, w: 8, h: 0.6,
      fontFace: D.b, fontSize: 28, color: D.accent, italic: true, align: "center", margin: 0
    });
  }
  s.addNotes(d.notes || "");
  return s;
}

function exercise(pres, lines, opts = {}) {
  const s = darkSlide(pres);
  const textItems = lines.map((line, i) => ({
    text: line.text,
    options: {
      fontFace: line.small ? D.b : D.h,
      fontSize: line.small ? 22 : (line.large ? 36 : 28),
      color: line.small ? D.muted : D.accent,
      bold: !line.small,
      italic: line.small,
      breakLine: i < lines.length - 1
    }
  }));
  s.addText(textItems, {
    x: 1.0, y: 1.0, w: 8, h: 3.6,
    align: "center", margin: 0, valign: "middle"
  });
  if (opts.notes) s.addNotes(opts.notes);
  return s;
}

// Four-step horizontal flow — matches ai-best-practices chain flow (Slide 54)
function stepsSlide(pres, steps, opts = {}) {
  const s = darkSlide(pres);
  const boxW = 1.8, boxH = 0.9, gap = 0.6;
  const totalW = steps.length * boxW + (steps.length - 1) * gap;
  const startX = (10 - totalW) / 2;
  steps.forEach((step, i) => {
    const x = startX + i * (boxW + gap);
    const hl = step.highlight;
    s.addShape(pres.shapes.ROUNDED_RECTANGLE, {
      x, y: 2.2, w: boxW, h: boxH,
      rectRadius: 0.1,
      fill: { color: hl ? D.accent : D.bg },
      line: hl ? undefined : { color: D.muted, width: 1.5 }
    });
    s.addText(step.label, {
      x, y: 2.2, w: boxW, h: boxH,
      fontFace: D.b, fontSize: 18, color: hl ? D.white : D.text,
      bold: true, align: "center", margin: 0, valign: "middle"
    });
    if (i < steps.length - 1) {
      s.addText("\u2192", {
        x: x + boxW, y: 2.2, w: gap, h: boxH,
        fontFace: D.b, fontSize: 28, color: D.accent, bold: true, align: "center", margin: 0, valign: "middle"
      });
    }
  });
  if (opts.subtitle) {
    s.addText(opts.subtitle, {
      x: 1.0, y: 3.6, w: 8, h: 0.6,
      fontFace: D.b, fontSize: 24, color: D.muted, italic: true, align: "center", margin: 0
    });
  }
  if (opts.notes) s.addNotes(opts.notes);
  return s;
}

// Giant number — matches ai-best-practices bigNum
function bigNum(pres, number, caption, opts = {}) {
  const s = darkSlide(pres);
  s.addText(number, {
    x: 0.5, y: 1.0, w: 9, h: 2.5,
    fontFace: D.h, fontSize: opts.numSize || 120,
    color: opts.color || D.white, bold: true, align: "center", margin: 0, valign: "bottom"
  });
  s.addText(caption, {
    x: 1.5, y: 3.6, w: 7, h: 0.8,
    fontFace: D.b, fontSize: 28, color: D.muted, align: "center", margin: 0, valign: "top"
  });
  if (opts.notes) s.addNotes(opts.notes);
  return s;
}

